
import React, { useEffect, useState } from 'react'

import * as _Util from '../../store/Util'

import '../../styles/_styles.css'
import { Icon_Cmpt } from '.'

const Icon2 = Icon_Cmpt()


const SearchProdComponent = (props) => {

  const {
    placeholderCode
  } = props;
  

  const [initialize, setInitialize] = useState(false);
  const [txt, settxt] = useState("");



  useEffect(() => {
    
    if(!initialize){
      setInitialize(true);
    }
  })

  const handleInput = (v) => {
    settxt(v.target.value)
    if(typeof props.updChanges === "function"){
      props.updChanges(v.target.value);
    }
  }

  const clearTx = (v) => {
    settxt("");
    document.getElementById("SREsRA").value = "";
    if(typeof props.updChanges === "function"){
      props.updChanges("");
    }
  }



  let isOpen = false;

  return (


    <div className={`z86TMb ${isOpen?"FNFY6c":""}`}>
      <button className="FrV7Ge" type="button"  aria-label="Buscar con Google" >
        <div className="kzJn9c">
          <span className="Vx3Zn">
            <Icon2 name={`search`} />
          </span>
        </div>
      </button>
      <input 
        className="r7gAOb yyJm8b" 
        max-length="2048" 
        id="SREsRA" 
        name="q" 
        type="text" 
        aria-autocomplete="both" 
        aria-haspopup="false" 
        auto-capitalize="off" 
        auto-complete="off" 
        auto-correct="off" 
        spell-check="false" 
        placeholder={_Util.translatetext(placeholderCode)}
        onChange={handleInput}
      />
      <button className="hxXCL" type="button" style={{visibility:txt.length>0?"":"hidden"}} >
        <span aria-label="Borrar búsqueda" onClick={clearTx} >×</span>
      </button>
    </div>
  )

}



export default SearchProdComponent;